import request from '@/utils/request'

export const auth = {
  login: async (data) => {
    console.log('Login Request Data:', data)
    try {
      const response = await request({
        url: '/api/v1/users/auth/login/password/',
        method: 'post',
        data: {
          phone: data.phone.trim(),
          password: data.password
        }
      })
      console.log('Login Response:', response)
      return response
    } catch (error) {
      console.error('Login Error:', error)
      if (error.response?.data) {
        const errorData = error.response.data
        if (errorData.message?.includes('账号不存在')) {
          error.code = 'user_not_found'
        } else if (errorData.message?.includes('密码错误')) {
          error.code = 'invalid_password'
        }
      }
      throw error
    }
  },

  logout: () => {
    const token = localStorage.getItem('access_token')
    if (!token) {
      console.warn('No token found for logout')
      return Promise.resolve()
    }

    return request({
      url: '/api/v1/users/auth/logout/',
      method: 'post',
      headers: {
        'Authorization': `Bearer ${token}`,
        'Accept': 'application/json',
        'Content-Type': 'application/json'
      }
    }).catch(error => {
      if (error.response?.status === 401) {
        console.warn('Token already expired during logout')
        return Promise.resolve()
      }
      throw error
    })
  },

  refreshToken: (data) => {
    return request({
      url: '/api/v1/users/auth/token/refresh/',
      method: 'post',
      data
    })
  },

  register: async (data) => {
    console.log('Register Request Data:', data)
    try {
      const registerData = {
        phone: data.phone.trim(),
        password: data.password,
        code: data.code
      }
      const response = await request({
        url: '/api/v1/users/auth/register/',
        method: 'post',
        data: registerData
      })
      console.log('Register Response:', response)
      return response
    } catch (error) {
      console.error('Register Error:', error)
      throw error
    }
  },

  sendVerifyCode: async (data) => {
    console.log('Send Code Request Data:', data)
    try {
      const response = await request({
        url: '/api/v1/users/auth/sms/send/',
        method: 'post',
        data: {
          phone: data.phone.trim(),
          scene: data.scene
        }
      })
      console.log('Send Code Response:', response)
      return response
    } catch (error) {
      console.error('Send Code Error:', error)
      throw error
    }
  }
}
